import json
import os
import logging
from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO"))

sns = boto3.client("sns")

DEFAULT_SUBJECTS = {
    "info": "Information Notification",
    "warning": "Warning Notification",
    "error": "Error Notification",
    "success": "Success Notification",
    "event": "Event Notification",
}


def build_message_payload(
    notification_type: str,
    message: Any,
    event: Dict[str, Any],
) -> Dict[str, Any]:
    if notification_type == "json":
        if isinstance(message, dict):
            return message
        if isinstance(message, str):
            try:
                return json.loads(message)
            except json.JSONDecodeError:
                return {"message": message}
        return {"message": message}

    if notification_type == "structured":
        return {
            "type": notification_type,
            "message": message,
            "source": event.get("source", "lambda"),
            "event_id": event.get("event_id"),
            "timestamp": event.get("timestamp"),
            "details": event.get("details", {}),
        }

    return {
        "type": notification_type or "event",
        "message": message,
        "metadata": event.get("metadata", {}),
    }


def resolve_subject(notification_type: str, event: Dict[str, Any]) -> str:
    return event.get("subject") or DEFAULT_SUBJECTS.get(notification_type, "SNS Notification")


def resolve_message_attributes(notification_type: str, event: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    attributes = {
        "notificationType": {
            "DataType": "String",
            "StringValue": notification_type or "event",
        }
    }

    custom_attributes = event.get("message_attributes", {})
    for key, value in custom_attributes.items():
        if isinstance(value, dict) and {"DataType", "StringValue"} <= value.keys():
            attributes[key] = {
                "DataType": str(value["DataType"]),
                "StringValue": str(value["StringValue"]),
            }
        else:
            attributes[key] = {
                "DataType": "String",
                "StringValue": str(value),
            }

    return attributes


def publish_to_sns(
    topic_arn: str,
    message: str,
    subject: Optional[str] = None,
    message_attributes: Optional[Dict[str, Dict[str, str]]] = None,
) -> Dict[str, Any]:
    params: Dict[str, Any] = {
        "TopicArn": topic_arn,
        "Message": message,
    }

    if subject:
        params["Subject"] = subject

    if message_attributes:
        params["MessageAttributes"] = message_attributes

    response = sns.publish(**params)
    return {
        "message_id": response.get("MessageId"),
        "topic_arn": topic_arn,
    }


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event, default=str))

    topic_arn = event.get("topic_arn") or event.get("topicArn")
    message = event.get("message")
    notification_type = str(event.get("notification_type", "event")).lower()

    if not topic_arn:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Missing required field: topic_arn"}),
        }

    if message is None:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Missing required field: message"}),
        }

    try:
        payload = build_message_payload(notification_type, message, event)
        subject = resolve_subject(notification_type, event)
        message_attributes = resolve_message_attributes(notification_type, event)

        result = publish_to_sns(
            topic_arn=topic_arn,
            message=json.dumps(payload, default=str),
            subject=subject,
            message_attributes=message_attributes,
        )

        logger.info("Published SNS message: %s", json.dumps(result))
        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "status": "published",
                    "message_id": result["message_id"],
                    "topic_arn": result["topic_arn"],
                    "notification_type": notification_type,
                }
            ),
        }

    except ClientError as e:
        logger.exception("SNS publish failed")
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Failed to publish message to SNS",
                    "details": str(e),
                }
            ),
        }
    except Exception as e:
        logger.exception("Unhandled error")
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Unhandled exception",
                    "details": str(e),
                }
            ),
        }